blocks.body:
{
    "level": "A2",
    "intro": "W tym temacie poznasz podstawowy model strony biernej: jak zbudować zdanie, jak zamienić active na passive i kiedy taka konstrukcja brzmi naturalnie.",
    "rules": [
        {
            "label": "Formuła",
            "color": "emerald",
            "text": "Podstawowy wzór strony biernej to <strong>subject + be + V3</strong>.",
            "example": "The cake is baked. — Ciasto jest pieczone / upieczone."
        },
        {
            "label": "Zmiana ról",
            "color": "blue",
            "text": "Dopełnienie zdania czynnego staje się podmiotem zdania biernego.",
            "example": "Tom writes letters. → Letters are written by Tom."
        },
        {
            "label": "by + agent",
            "color": "rose",
            "text": "Fraza <strong>by + agent</strong> pokazuje wykonawcę czynności, ale nie zawsze jest potrzebna.",
            "example": "The book was written by Shakespeare."
        }
    ]
}

{
    "title": "1. Stan aktywny i pasywny",
    "intro": "Porównanie stanu aktywnego i pasywnego:",
    "items": [
        {
            "label": "Aktywny",
            "title": "Podmiot wykonuje akcję",
            "subtitle": "Tomek pisze listy. — Tomek pisze do listy."
        },
        {
            "label": "Pasywny",
            "title": "Podmiot otrzymuje akcję",
            "subtitle": "Listy pisze Tomek. — Listy pisze Tomek."
        },
        {
            "label": "Formuła",
            "title": "być + V3",
            "subtitle": "Czasownik be występuje w czasie właściwym + imiesłów bierny."
        },
        {
            "label": "Agent",
            "title": "przez + wykonawcę",
            "subtitle": "Określono, czy znajomość wykonawcy jest ważna."
        }
    ]
}

{
    "title": "2. Jak zamienić active na passive?",
    "sections": [
        {
            "label": "Krok 1",
            "color": "emerald",
            "description": "Dopełnienie zdania czynnego staje się nowym <strong>podmiotem</strong> zdania biernego.",
            "examples": [
                {
                    "en": "Active: Tom writes letters.",
                    "ua": "letters → nowy podmiot: Letters"
                },
                {
                    "en": "Active: They built a house.",
                    "ua": "a house → nowy podmiot: A house"
                }
            ]
        },
        {
            "label": "Krok 2",
            "color": "blue",
            "description": "Dodaj odpowiednią formę <strong>be</strong> i czasownik w <strong>V3</strong>.",
            "examples": [
                {
                    "en": "writes → is / are written",
                    "ua": "Present Simple Passive: am / is / are + V3"
                },
                {
                    "en": "built → was / were built",
                    "ua": "Past Simple Passive: was / were + V3"
                }
            ]
        },
        {
            "label": "Krok 3",
            "color": "rose",
            "description": "Dawny podmiot możesz dodać jako <strong>by + agent</strong>, jeśli informacja o wykonawcy jest ważna.",
            "examples": [
                {
                    "en": "Tom → by Tom",
                    "ua": "Dodajemy wykonawcę, gdy ma znaczenie."
                },
                {
                    "en": "They → (often omitted)",
                    "ua": "Pomijamy wykonawcę, gdy jest nieznany albo nieistotny."
                }
            ]
        }
    ]
}

{
    "title": "3. Przykłady konwersji Aktywna → Pasywna",
    "intro": "Pełny proces konwersji zdań czynnych na bierne:",
    "rows": [
        {
            "en": "Active: Mary bakes a cake.",
            "ua": "Maria piecze ciasto.",
            "note": "→ Passive: A cake is baked by Mary."
        },
        {
            "en": "Active: They speak English here.",
            "ua": "Mówi się tu po angielsku.",
            "note": "→ Passive: English is spoken here."
        },
        {
            "en": "Active: Someone stole my bike.",
            "ua": "Ktoś ukradł mój rower.",
            "note": "→ Passive: My bike was stolen."
        },
        {
            "en": "Active: The company will hire new employees.",
            "ua": "Firma zatrudni nowych pracowników.",
            "note": "→ Passive: New employees will be hired by the company."
        }
    ],
    "warning": "📌 by + agent jest pomijany, jeśli artysta jest nieznany, nieistotny lub oczywisty!"
}

{
    "title": "4. Kiedy używać strony biernej?",
    "sections": [
        {
            "label": "Nieznany artysta",
            "color": "emerald",
            "description": "Gdy <strong>nie wiadomo</strong>, kto wykonał czynność:",
            "examples": [
                {
                    "en": "My car was stolen last night.",
                    "ua": "Wczoraj w nocy skradziono mi samochód."
                },
                {
                    "en": "The window has been broken.",
                    "ua": "Okno jest rozbite."
                },
                {
                    "en": "The building was destroyed.",
                    "ua": "Budynek został zniszczony."
                }
            ]
        },
        {
            "label": "Nieważny wykonawca",
            "color": "blue",
            "description": "Kiedy wykonawca jest <strong>nieważny</strong> lub oczywisty:",
            "examples": [
                {
                    "en": "The streets are cleaned every day.",
                    "ua": "Ulice są sprzątane codziennie."
                },
                {
                    "en": "Tickets are sold at the entrance.",
                    "ua": "Bilety sprzedawane są przy wejściu."
                },
                {
                    "en": "The law was passed last year.",
                    "ua": "Ustawa została przyjęta w zeszłym roku."
                }
            ]
        },
        {
            "label": "Skoncentruj się na działaniu/przedmiocie",
            "color": "amber",
            "description": "Kiedy <strong>akcja</strong> lub <strong>przedmiot</strong> jest ważniejsza:",
            "examples": [
                {
                    "en": "The report was submitted on time.",
                    "ua": "Raport został złożony w terminie."
                },
                {
                    "en": "The new system will be launched tomorrow.",
                    "ua": "Nowy system zostanie uruchomiony jutro."
                },
                {
                    "en": "The product is made in Germany.",
                    "ua": "Produkt wyprodukowany jest w Niemczech."
                }
            ]
        },
        {
            "label": "Styl formalny",
            "color": "rose",
            "description": "W stylu <strong>naukowym, oficjalnym</strong> i <strong>biznesowym</strong>:",
            "examples": [
                {
                    "en": "The experiment was conducted carefully.",
                    "ua": "Eksperyment został przeprowadzony starannie."
                },
                {
                    "en": "Applicants will be notified by email.",
                    "ua": "Kandydaci zostaną powiadomieni e-mailem."
                },
                {
                    "en": "The data is analyzed weekly.",
                    "ua": "Dane są analizowane co tydzień."
                }
            ]
        }
    ]
}

{
    "title": "5. By vs With w stronie biernej",
    "intro": "Różnica między <strong>by</strong> i <strong>with</strong> w zdaniach pasywnych:",
    "items": [
        {
            "label": "przez",
            "title": "Kto wykonuje czynność (agent)",
            "subtitle": "Książka została napisana przez Marka Twaina."
        },
        {
            "label": "z",
            "title": "Co/za pomocą czego (instrument)",
            "subtitle": "List został napisany piórem."
        },
        {
            "label": "przez",
            "title": "Żywa istota lub organizacja",
            "subtitle": "Projekt został zrealizowany przez nasz zespół."
        },
        {
            "label": "z",
            "title": "Narzędzie, materiał",
            "subtitle": "Tort udekorowano czekoladą."
        }
    ]
}

{
    "title": "6. Typowe błędy",
    "items": [
        {
            "label": "Błąd 1",
            "color": "rose",
            "title": "Pominięcie czasownika be.",
            "wrong": "The letter written yesterday.",
            "right": "✅ The letter was written yesterday."
        },
        {
            "label": "Błąd 2",
            "color": "amber",
            "title": "Użycie V1 albo V2 zamiast V3.",
            "wrong": "English is speak here.",
            "right": "✅ English is spoken here."
        },
        {
            "label": "Błąd 3",
            "color": "sky",
            "title": "Użycie with zamiast by do wykonawcy.",
            "wrong": "The book was written with Shakespeare.",
            "right": "✅ The book was written by Shakespeare."
        },
        {
            "label": "Błąd 4",
            "color": "rose",
            "title": "Zbędne dopowiadanie wykonawcy.",
            "wrong": "My car was stolen by someone.",
            "right": "✅ My car was stolen. (wykonawca jest nieznany lub nieistotny)"
        }
    ]
}
